import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static final AuthManager _instance = AuthManager._internal();
  factory AuthManager() => _instance;
  AuthManager._internal();

  SharedPreferences? _prefs;

  Future<void> initPrefs() async {
    _prefs = await SharedPreferences.getInstance();
  }

  Future<bool> login(String token, String userData) async {
    if (_prefs == null) {
      await initPrefs();
    }
    await _prefs?.setString('authToken', token);
    await _prefs?.setString('userData', userData);
    return true;
  }

  Future<String?> getToken() async {
    if (_prefs == null) {
      await initPrefs();
    }
    return _prefs?.getString('authToken');
  }

  Future<String?> getUserData() async {
    if (_prefs == null) {
      await initPrefs();
    }
    return _prefs?.getString('userData');
  }

  Future<bool> logout() async {
    if (_prefs == null) {
      await initPrefs();
    }
    await _prefs?.remove('authToken');
    await _prefs?.remove('userData');
    return true;
  }
}

